  //---------------------------------------------------------------------
  //---------------------------------------------------------------------
  ::grpc::Status NiRFmxWLANGenService::OpenSession(::grpc::ServerContext* context, const OpenSessionRequest* request, OpenSessionResponse* response)
  {
    if (context->IsCancelled()) {
      return ::grpc::Status::CANCELLED;
    }
    try {
      auto session_name_mbcs = convert_from_grpc<std::string>(request->session_name());
      char* session_name = (char*)session_name_mbcs.c_str();
      int32 toolkit_compatibility_version;
      switch (request->toolkit_compatibility_version_enum_case()) {
        case nirfmxwlangen_grpc::OpenSessionRequest::ToolkitCompatibilityVersionEnumCase::kToolkitCompatibilityVersion: {
          toolkit_compatibility_version = static_cast<int32>(request->toolkit_compatibility_version());
          break;
        }
        case nirfmxwlangen_grpc::OpenSessionRequest::ToolkitCompatibilityVersionEnumCase::kToolkitCompatibilityVersionRaw: {
          toolkit_compatibility_version = static_cast<int32>(request->toolkit_compatibility_version_raw());
          break;
        }
        case nirfmxwlangen_grpc::OpenSessionRequest::ToolkitCompatibilityVersionEnumCase::TOOLKIT_COMPATIBILITY_VERSION_ENUM_NOT_SET: {
          return ::grpc::Status(::grpc::INVALID_ARGUMENT, "The value for toolkit_compatibility_version was not specified or out of range");
          break;
        }
      }


      int32 is_new_session {};
      auto init_lambda = [&] () {
        niWLANGenerationSession session;
        auto status = library_->OpenSession(session_name, toolkit_compatibility_version, &session, &is_new_session);
        return std::make_tuple(status, session);
      };
      std::string grpc_device_session_name = request->session_name();
      // Capture the library shared_ptr by value. Do not capture `this` or any references.
      LibrarySharedPtr library = library_;
      auto cleanup_lambda = [library] (niWLANGenerationSession id) { library->CloseSession(id); };
      int status = session_repository_->add_session(grpc_device_session_name, init_lambda, cleanup_lambda);
      if (!status_ok(status)) {
        return ConvertApiErrorStatusForNiWLANGenerationSession(context, status, 0);
      }
      response->set_status(status);
      response->mutable_session()->set_name(grpc_device_session_name);
      response->set_is_new_session(is_new_session);
      return ::grpc::Status::OK;
    }
    catch (nidevice_grpc::NonDriverException& ex) {
      return ex.GetStatus();
    }
  }

